create table bnc_us_norm
(
    ano                   bigint,
    mes                   bigint,
    semana                bigint,
    referencia_bancaria   bigint,
    descripcion           text,
    monto_ref             double precision,
    saldo_ref             double precision,
    moneda_ref            text,
    tasa_cambio           bigint,
    monto_usd             double precision,
    concepto_ey           double precision,
    proveedor_cliente     double precision,
    tipo_operacion        text,
    banco                 text,
    fecha_carga           timestamp,
    es_saldo_final        boolean,
    saldo_final_calculado double precision,
    fecha                 date not null
);

alter table bnc_us_norm
    owner to postgres;

